    dyd_b2_base32_char_shell_append $((((dyd_b2_d12 & 15) << 1) | (dyd_b2_d13 >> 7)))
    dyd_b2_base32_char_shell_append $(((dyd_b2_d13 >> 2) & 31))
    dyd_b2_base32_char_shell_append $((((dyd_b2_d13 & 3) << 3) | (dyd_b2_d14 >> 5)))
    dyd_b2_base32_char_shell_append $((dyd_b2_d14 & 31))
    dyd_b2_base32_char_shell_append $((dyd_b2_d15 >> 3))
    dyd_b2_base32_char_shell_append $(((dyd_b2_d15 & 7) << 2))
    dyd_ret0=$dyd_b2_base32_output
}

dyd_b2_hash_file_shell () {
    dyd_b2_file=$1
    dyd_b2_format=${2:-hex}
    dyd_b2_od_tmp=${TMPDIR:-/tmp}/dryad-sh-hash-od.$$
    rm -f "$dyd_b2_od_tmp"
    if ! od -An -v -tu1 -w128 "$dyd_b2_file" > "$dyd_b2_od_tmp"; then
        rm -f "$dyd_b2_od_tmp"
        return 1
    fi
    dyd_b2_reset_shell
    dyd_b2_have_block=0
    dyd_b2_pending_line=
    while IFS= read -r dyd_b2_line; do
        [ -n "$dyd_b2_line" ] || continue
        if [ "$dyd_b2_have_block" = 1 ]; then
            set -- $dyd_b2_pending_line
            dyd_b2_load_block_shell "$@"
            dyd_b2_add_counter_shell "$dyd_b2_block_len"
            dyd_b2_compress_shell 0
        fi
        dyd_b2_pending_line=$dyd_b2_line
        dyd_b2_have_block=1
    done < "$dyd_b2_od_tmp"
    rm -f "$dyd_b2_od_tmp"
    if [ "$dyd_b2_have_block" = 1 ]; then
        set -- $dyd_b2_pending_line
        dyd_b2_load_block_shell "$@"
    else
        dyd_b2_load_block_shell
    fi
    dyd_b2_add_counter_shell "$dyd_b2_block_len"
    dyd_b2_compress_shell 1
    case $dyd_b2_format in
        base32 ) dyd_b2_output_base32_shell_load ;;
        hex ) dyd_b2_output_hex_shell_load ;;
        * ) dryad_die "unsupported shell hash format: $dyd_b2_format" ;;
    esac
}

dryad_blake2b_128_file_hex_shell_load () {
    dyd_b2_hash_file_shell "$1" hex
}

dryad_blake2b_128_file_base32_shell_load () {
    dyd_b2_hash_file_shell "$1" base32
}

dryad_blake2b_128_file_prefixed_base32_shell_load () {
    dyd_b2_prefixed_file=$1
    dyd_b2_od_tmp=${TMPDIR:-/tmp}/dryad-sh-hash-od.$$
    rm -f "$dyd_b2_od_tmp"
    if ! od -An -v -tu1 -w128 "$dyd_b2_prefixed_file" > "$dyd_b2_od_tmp"; then
        rm -f "$dyd_b2_od_tmp"
        return 1
    fi
    dyd_b2_reset_shell
    dyd_b2_have_block=0
    dyd_b2_loaded_block=0
    dyd_b2_pending_line=
    while IFS= read -r dyd_b2_line; do
        [ -n "$dyd_b2_line" ] || continue
        if [ "$dyd_b2_have_block" = 1 ]; then
            set -- $dyd_b2_pending_line
            if [ "$dyd_b2_loaded_block" = 0 ]; then
                dyd_b2_load_initial_prefixed_block_shell "$@"
            else
                dyd_b2_load_carried_prefixed_block_shell "$@"
            fi
            dyd_b2_add_counter_shell "$dyd_b2_block_len"
            dyd_b2_compress_shell 0
            dyd_b2_loaded_block=1
        fi
        dyd_b2_pending_line=$dyd_b2_line
        dyd_b2_have_block=1
    done < "$dyd_b2_od_tmp"
    rm -f "$dyd_b2_od_tmp"
    if [ "$dyd_b2_have_block" = 1 ]; then
        set -- $dyd_b2_pending_line
        if [ "$dyd_b2_loaded_block" = 0 ]; then
            dyd_b2_load_initial_prefixed_block_shell "$@"
        else
            dyd_b2_load_carried_prefixed_block_shell "$@"
        fi
    else
        dyd_b2_load_initial_prefixed_block_shell
    fi
    if [ "$dyd_b2_carry_len" -gt 0 ]; then
        dyd_b2_add_counter_shell "$dyd_b2_block_len"
        dyd_b2_compress_shell 0
        dyd_b2_load_final_carry_block_shell
    fi
    dyd_b2_add_counter_shell "$dyd_b2_block_len"
    dyd_b2_compress_shell 1
    dyd_b2_output_base32_shell_load
}
